	for (i = 0; i < NUM_THREADS; i++) {
		if (*r + step > end || *r + step * dir < 0)
			break;
		data[i].lb = lb;
		data[i].re = re;
		data[i].dir = dir;
		data[i].off = i ? 0 : off;
		rs[i] = *r + step * dir;
		step += thread_step;
		data[i].r = &rs[i];
		data[i].beg = beg;
